/// Per-row change emitted by wal-gateway. Subject pattern is '<prefix>.<schema>.<table>.<op>'. The default prefix is 'cdc' and the default stream name is 'CDC'. Consumers usually subscribe to the prefix tail wildcard ('cdc.>').
/// Service: dd-wal-gateway
const String cdcRowChangePattern = "{prefix}.{schema}.{table}.{op}";
const String cdcRowChangeWildcard = "{prefix}.>";
const String cdcRowChangeStream = "CDC";
class CdcRowChangeSubjectParts {
  final String prefix;
  final String schema;
  final String table;
  final String op;
  const CdcRowChangeSubjectParts({required this.prefix, required this.schema, required this.table, required this.op});
}

String cdcRowChangeSubject(String prefix, String schema, String table, String op) {
  return '$prefix.$schema.$table.$op';
}

CdcRowChangeSubjectParts? parseCdcRowChangeSubject(String subject) {
  final patternTokens = ["{prefix}","{schema}","{table}","{op}"];
  final subjectTokens = subject.split('.');
  if (patternTokens.length != subjectTokens.length) return null;
  final result = <String, String>{};
  for (var i = 0; i < patternTokens.length; i += 1) {
    final p = patternTokens[i];
    final s = subjectTokens[i];
    if (p.startsWith('{') && p.endsWith('}')) {
      result[p.substring(1, p.length - 1)] = s;
    } else if (p != s) {
      return null;
    }
  }
  return CdcRowChangeSubjectParts(prefix: result["prefix"]!, schema: result["schema"]!, table: result["table"]!, op: result["op"]!);
}

/// Per-table JetStream filter subject ('<prefix>.<schema>.<table>.>') used by CDC consumers (e.g. dd-remote-rest-api) to subscribe to every op for one Postgres table. Not a publish target; producers publish per-row via CdcRowChange.
